CREATE EXTENSION IF NOT EXISTS pg_cron; CREATE EXTENSION IF NOT EXISTS pg_net; DO $outer$ BEGIN PERFORM cron.unschedule('auto-generate-content-batch'); EXCEPTION WHEN OTHERS THEN NULL; END $outer$; SELECT cron.schedule('auto-generate-content-batch', '*/5 * * * *', $cron$ SELECT net.http_post(url := 'https://ptfjspcphskifoseidut.supabase.co/functions/v1/generate-content-batch', headers := jsonb_build_object('Content-Type', 'application/json', 'x-driver-secret', (SELECT decrypted_secret FROM vault.decrypted_secrets WHERE name = 'SUPABASE_SERVICE_ROLE_KEY' LIMIT 1)), body := jsonb_build_object('action', 'start', 'count', 10, 'model', 'google/gemini-3-flash-preview')); $cron$);